@charset "UTF-8";
/* Application globale de la police Poppins */
body {
  margin: 0;
  padding: 0;
  display: flex;
  justify-content: center;
  align-items: center;
  height: 100vh;
  background-color: #fafafa; /* Fond légèrement cassé pour faire ressortir la carte blanche */
  font-family: "Poppins", sans-serif;
}

.loading-container {
  width: 100%;
  max-width: 550px;
  padding: 20px;
}

/* --- EN-TÊTE ET LOGOS --- */
.header-section {
  text-align: center;
  margin-bottom: 32px;
}

.main-title {
  font-size: 18px;
  font-weight: 600;
  color: #111827;
  line-height: 1.4;
  margin-bottom: 24px;
}

.logos-container {
  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  gap: 12px;
}

/* Style des placeholders de logos */
.logo-badge {
  background-color: #ffffff;
  border: 1px solid #e5e7eb;
  color: #9ca3af;
  padding: 8px 16px;
  border-radius: 8px;
  font-size: 12px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  box-shadow: 0 1px 2px rgba(0, 0, 0, 0.05);
  /* Animation pour simuler l'interrogation des serveurs */
  animation: pulseLogo 3s infinite alternate;
}

/* Désynchronisation légère des logos pour un effet aléatoire */
.logo-badge:nth-child(2) {
  animation-delay: 0.5s;
}

.logo-badge:nth-child(3) {
  animation-delay: 1.2s;
}

.logo-badge:nth-child(4) {
  animation-delay: 0.8s;
}

.logo-badge:nth-child(5) {
  animation-delay: 2.1s;
}

.logo-badge:nth-child(6) {
  animation-delay: 1.5s;
}

@keyframes pulseLogo {
  0% {
    transform: scale(1);
    border-color: #e5e7eb;
    color: #9ca3af;
  }
  50% {
    transform: scale(1.05);
    border-color: #82DB35;
    color: #111827;
    box-shadow: 0 4px 6px rgba(130, 219, 53, 0.2);
  }
  100% {
    transform: scale(1);
    border-color: #e5e7eb;
    color: #9ca3af;
  }
}
/* --- BARRE DE PROGRESSION --- */
.progress-bar-container {
  width: 100%;
  height: 12px;
  background-color: #e5e7eb;
  border-radius: 20px;
  margin: 0 auto 32px auto;
  overflow: hidden;
  position: relative;
}

.progress-bar {
  height: 100%;
  width: 0%;
  background-color: #82DB35;
  border-radius: 20px;
  transition: width 0.4s ease-out;
  position: relative;
  overflow: hidden;
}

.progress-bar::after {
  content: "";
  position: absolute;
  top: 0;
  left: -100%;
  width: 50%;
  height: 100%;
  background: linear-gradient(90deg, rgba(255, 255, 255, 0) 0%, rgba(255, 255, 255, 0.6) 50%, rgba(255, 255, 255, 0) 100%);
  animation: shimmer 1.5s infinite linear;
}

@keyframes shimmer {
  100% {
    left: 200%;
  }
}
/* --- CARTE "LE SAVIEZ-VOUS" --- */
.info-card {
  background-color: #ffffff;
  border: 1px solid #f3f4f6;
  border-radius: 16px;
  padding: 24px;
  box-shadow: 0 10px 25px -5px rgba(0, 0, 0, 0.05), 0 8px 10px -6px rgba(0, 0, 0, 0.01);
  min-height: 120px;
  display: flex;
  flex-direction: column;
  justify-content: center;
}

.info-header {
  display: flex;
  align-items: center;
  margin-bottom: 12px;
}

.info-icon {
  font-size: 18px;
  margin-right: 8px;
}

.info-title {
  color: #82DB35; /* Ta couleur pour le titre */
  font-size: 14px;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  margin: 0;
  font-weight: 700;
}

#scramble-text {
  color: #374151;
  font-size: 15px;
  line-height: 1.6;
  margin: 0;
  font-weight: 500;
}

.dud {
  color: #d1d5db; /* Gris clair pour les lettres en cours de décryptage */
}

