// Tes 5 messages stratégiques
const messages = ["Mieux qu'un comparateur, Ideel est votre courtier : vous serez prévenu(e) si le tarif de votre assurance augmente.", "Ideel est 100% gratuit, vous pouvez soutenir le projet en devenant membre Ideel+ au prix que vous souhaitez.", "Ideel est noté 4,9 / 5 ⭐⭐⭐⭐⭐ avec une communauté de plus de 100 000 utilisateurs.", "En cas de problème avec votre assureur, Ideel prendra le relai pour vous directement auprès du service client.", "Vous pourrez finaliser la souscription à la prochaine étape, Ideel s'occupera de toutes les démarches administratives pour vous."];

// Classe pour l'animation "Scramble"
class TextScramble {
  constructor(el) {
    this.el = el;
    this.chars = '!<>-_\\/[]{}—=+*^?#________ABCDEFGHIJKLMNOPQRSTUVWXYZ';
    this.update = this.update.bind(this);
  }
  setText(newText) {
    const oldText = this.el.innerText;
    const length = Math.max(oldText.length, newText.length);
    const promise = new Promise(resolve => this.resolve = resolve);
    this.queue = [];
    for (let i = 0; i < length; i++) {
      const from = oldText[i] || '';
      const to = newText[i] || '';
      const start = Math.floor(Math.random() * 40);
      const end = start + Math.floor(Math.random() * 40);
      this.queue.push({
        from,
        to,
        start,
        end
      });
    }
    cancelAnimationFrame(this.frameRequest);
    this.frame = 0;
    this.update();
    return promise;
  }
  update() {
    let output = '';
    let complete = 0;
    for (let i = 0, n = this.queue.length; i < n; i++) {
      let {
        from,
        to,
        start,
        end,
        char
      } = this.queue[i];
      if (this.frame >= end) {
        complete++;
        output += to;
      } else if (this.frame >= start) {
        if (!char || Math.random() < 0.28) {
          char = this.randomChar();
          this.queue[i].char = char;
        }
        output += `<span class="dud">${char}</span>`;
      } else {
        output += from;
      }
    }
    this.el.innerHTML = output;
    if (complete === this.queue.length) {
      this.resolve();
    } else {
      this.frameRequest = requestAnimationFrame(this.update);
      this.frame++;
    }
  }
  randomChar() {
    return this.chars[Math.floor(Math.random() * this.chars.length)];
  }
}
appsmith.onReady(() => {
  // 1. GESTION DES MESSAGES "LE SAVIEZ-VOUS"
  const textElement = document.getElementById('scramble-text');
  const fx = new TextScramble(textElement);
  let currentMessageIndex = 0;
  fx.setText(messages[currentMessageIndex]);

  // On change le message toutes les 6 secondes (6s * 5 messages = 30s)
  const textInterval = setInterval(() => {
    currentMessageIndex++;
    if (currentMessageIndex < messages.length) {
      fx.setText(messages[currentMessageIndex]);
    }
  }, 6000);

  // 2. GESTION DE LA BARRE DE PROGRESSION
  const progressBar = document.getElementById('progress-bar');
  let currentProgress = 0;
  const totalDuration = 30000; // 30 secondes
  const updateInterval = 800;
  const averageIncrement = 100 / (totalDuration / updateInterval);
  const progressInterval = setInterval(() => {
    let randomFactor = 0.2 + Math.random() * 1.6;
    currentProgress += averageIncrement * randomFactor;
    if (currentProgress >= 100) {
      currentProgress = 100;
      clearInterval(progressInterval);
      clearInterval(textInterval);
      progressBar.style.width = `100%`;
      setTimeout(() => {
        appsmith.triggerEvent("onTimerEnd");
      }, 500);
    } else {
      progressBar.style.width = `${currentProgress}%`;
    }
  }, updateInterval);
});

